import { Component, OnInit } from "@angular/core";
import { DatePipe, formatNumber } from "@angular/common";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { CalcMethod } from "src/app/views/Models/Loan/CalcMethod";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { AlertService } from "src/app/core/services/alert.service";
import {
  LoanRejectionParent,
  RejectionReason,
} from "src/app/views/Models/Loan/Rejection";
import { IBusinessDivisions } from "src/app/views/Models/References/BusinessDivisions";
import { IBusinessDivisionsActivityTypes } from "src/app/views/Models/References/BusinessDivisionsType";
import { IBusinessDivisionsActivitySpec } from "src/app/views/Models/References/BusinessDivisionsSpec";
import { IBusinessAll } from "src/app/views/Models/References/BusinessAll";
import { ReferencesService } from "src/app/core/services/references.service";
import { Node, Tree } from "src/app/views/Models/Users/Tree";

@Component({
  selector: "app-rejection-reason",
  templateUrl: "./rejection-reason.page.html",
  styleUrls: ["./rejection-reason.page.css"],
})
export class RejectionReasonPage implements OnInit {
  showLoader: boolean = false;
  rejectionReasons: RejectionReason[];
  RejRefTypes: LoanRejectionParent[];
  rejectionInfo: RejectionReason;
  LoanRejectionParentInfo: LoanRejectionParent;
  isSubmitted: boolean = false;
  isInserting: boolean = false;
  isEditing: boolean = false;
  TreeNodes: Tree<Node>[];
  currentTreeNode: Tree<Node>;

  hasSupervisor: boolean = false;
  sortingIconClass: string;
  sortingIconParam: string;
  // nodeMap: Record<number, TreeNodes> = [];

  rejectionReasonForm: FormGroup = this.formBuilder.group({
    tree_code: [""],
    tree_name: ["", [Validators.required]],
    active_rec: [""],
  });
  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }

  constructor(
    private formBuilder: FormBuilder,
    private datepipe: DatePipe,
    private http: HttpClient,
    private env: EnvService,
    private alertServices: AlertService
  ) {}

  ngOnInit() {
    this.loadRejectionReasons();
  }

  loadRejectionReasons() {
    this.showLoader = true;
    this.TreeNodes = [
      {
        data: {
          node_code: 0,
          active_rec: null,
          parent_id: null,
        },
        text: "اسباب الرفض الرئيسية",
        collapsed: true,
        canEdit: false,
        canDelete: false,
        canSelect: false,
        canAdd: true,
        initialized: false,
      },
    ];
    this.http
      .get<LoanRejectionParent[]>(this.env.API_URL + "api/Rej/GetRejParent")
      .subscribe({
        next: (Rejs_1) => {
          this.TreeNodes = this.TreeNodes.map((treeNode) => ({
            ...treeNode,
            children: Rejs_1.filter(
              (Rej_1) => treeNode.data.node_code == 0
            ).map<Tree<Node>>((Rej_1) => ({
              data: {
                node_code: parseInt(Rej_1.parent_rej_code),
                active_rec: null,
                parent_id: 0,
              },
              text: Rej_1.parent_rej_desc,
              children_id: null,
              collapsed: true,
              canEdit: true,
              canDelete: true,
              canSelect: false,
              canAdd: true,
              initialized: false,
            })),
          }));
          this.http
            .get<RejectionReason[]>(this.env.API_URL + "api/Rej/GetRejAll")
            .subscribe({
              next: (Rejs_2) => {
                this.TreeNodes = this.TreeNodes.map<Tree<Node>>((treeNode) => ({
                  ...treeNode,
                  children: treeNode.children?.map<Tree<Node>>((child) => ({
                    ...child,
                    children: Rejs_2.filter(
                      (Rej_2) =>
                        child.data.node_code ==
                          parseInt(Rej_2.parent_rej_code) &&
                        treeNode.data.node_code == 0
                    ).map<Tree<Node>>((Rejs_2) => ({
                      data: {
                        node_code: parseInt(Rejs_2.loan_rej_code),
                        active_rec: Rejs_2.active_rec,
                        parent_id: parseInt(Rejs_2.parent_rej_code),
                      },
                      text: Rejs_2.loan_rej_desc,
                      collapsed: true,
                      canEdit: true,
                      canDelete: true,
                      canAdd: false,
                      canSelect: false,
                      initialized: false,
                    })),
                  })),
                }));
                this.showLoader = false;
              },
            });
        },
      });
  }
  Edit(node: Tree<Node>): void {
    this.hasSupervisor = false;
    this.currentTreeNode = node;
    console.log(node);
    console.log(this.TreeNodes);
    if (node.data.parent_id != null && node.children) {
      this.GetRej1ByID(node.data.node_code, true);
    }
    if (node.data.parent_id != null && !node.children) {
      this.GetRej2ByID(node.data.node_code, node.data.parent_id, true);
    }
  }

  async Delete(node: Tree<Node>): Promise<void> {
    this.hasSupervisor = false;
    this.currentTreeNode = node;
    if (await this.alertServices.SaveAlert("هل تريد الحذف؟")) {
      if (node.data.parent_id != null && !!node.children) {
        this.showLoader = true;
        this.http
          .post(this.env.API_URL + "api/Rej/RejParantDel", {
            parent_rej_code: node.data.node_code.toString(),
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحذف بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
      if (node.data.parent_id != null && !node.children) {
        this.showLoader = true;
        this.http
          .post(this.env.API_URL + "api/Rej/RejRefDel", {
            loan_rej_code: node.data.node_code.toString(),
            parent_rej_code: node.data.parent_id.toString(),
          })
          .subscribe({
            next: (data) => {
              this.showLoader = false;
              this.alertServices.showAlertConfirm("تم الحذف بنجاح", true);
            },
            error: (err) => {
              console.log(err);
              this.alertServices.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      }
    }
  }

  Add(node: Tree<Node>): void {
    this.currentTreeNode = node;
    if (node.data.parent_id == null && !!node.children) {
      this.GetRej1Insert(true);
    }
    if (node.data.parent_id != null && !!node.children) {
      this.GetRej2Insert(true);
    }

    this.isInserting = this.isInserting;
    this.showLoader = false;
    this.hasSupervisor = true;
  }
  async GetRej1Insert(isInserting) {
    if (isInserting) this.Rej1Insert();
    this.isInserting = isInserting;
    this.showLoader = false;
  }
  Rej1Insert() {
    this.rejectionReasonForm.patchValue({
      tree_name: " ",
      tree_code: 0,
      active_rec: 0,
    });
  }
  async GetRej2Insert(isInserting) {
    if (isInserting) this.Rej2Insert();
    this.isInserting = isInserting;
    this.showLoader = false;
  }
  Rej2Insert() {
    this.rejectionReasonForm.patchValue({
      tree_name: " ",
      tree_code: 0,
      active_rec: 0,
    });
  }
  async GetRej1ByID(parent_rej_code, isEditing) {
    this.http
      .get<LoanRejectionParent>(
        `${this.env.API_URL}api/Rej/GetRejParentByCode?parent_rej_code=${parent_rej_code}`
      )
      .subscribe({
        next: (data) => {
          this.LoanRejectionParentInfo = data;
          if (isEditing) this.patchDataValue();
          this.isEditing = isEditing;
          this.showLoader = false;
        },

        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }

  patchDataValue() {
    this.rejectionReasonForm.patchValue({
      tree_name: this.LoanRejectionParentInfo[0].parent_rej_desc,
      tree_code: this.LoanRejectionParentInfo[0].parent_rej_code,
      active_rec: this.LoanRejectionParentInfo[0].active_rec,
    });
  }
  GetRej2ByID(loan_rej_code, parent_rej_code, isEditing) {
    this.http
      .get<RejectionReason>(
        `${this.env.API_URL}api/Rej/GetRejByCode?loan_rej_code=${loan_rej_code}&parent_rej_code=${parent_rej_code}`
      )
      .subscribe({
        next: (data) => {
          console.log(data);
          this.rejectionInfo = data;
          if (isEditing) this.GetNestedRejection();
          this.isEditing = isEditing;
          this.showLoader = false;
        },

        error: (err) => {
          console.log(err);
          this.showLoader = false;
        },
      });
  }
  GetNestedRejection() {
    console.log(this.rejectionInfo);
    this.rejectionReasonForm.patchValue({
      tree_name: this.rejectionInfo[0].loan_rej_desc,
      tree_code: this.rejectionInfo[0].loan_rej_code,
      active_rec: this.rejectionInfo[0].active_rec,
    });
  }
  async EditRej() {
    let node: Tree<Node> = this.currentTreeNode;
    console.log(
      node,
      node.data.parent_id != null && !!node.children,
      node.data.parent_id != null && !node.children
    );
    if (this.rejectionReasonForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد تعديل البيانات؟")) {
        if (node.data.parent_id != null && !!node.children) {
          this.showLoader = true;
          this.http
            .post(this.env.API_URL + "api/Rej/RejectionParent", {
              parent_rej_code: node.data.node_code.toString(),
              parent_rej_desc:
                this.rejectionReasonForm.value.tree_name.toString(),
              active_rec:
                this.rejectionReasonForm.value.active_rec == "1" ? "1" : "0",
            })
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        }
        if (node.data.parent_id != null && !node.children) {
          this.showLoader = true;
          console.log({
            loan_rej_code: node.data.node_code.toString(),
            loan_rej_desc: this.rejectionReasonForm.value.tree_name.toString(),
            active_rec:
              this.rejectionReasonForm.value.active_rec == "1" ? "1" : "0",
            parent_rej_code: node.data.parent_id,
          });
          this.http
            .post(this.env.API_URL + "api/LoanApplications/UpdateRejection", {
              loan_rej_code: node.data.node_code.toString(),
              loan_rej_desc:
                this.rejectionReasonForm.value.tree_name.toString(),
              active_rec:
                this.rejectionReasonForm.value.active_rec == "1" ? "1" : "0",
              parent_rej_code: node.data.parent_id.toString(),
            })
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        }
      }
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }
  async InsertRej() {
    let node: Tree<Node> = this.currentTreeNode;
    if (this.rejectionReasonForm.valid) {
      if (await this.alertServices.SaveAlert("هل تريد الاضافة؟")) {
        if (node.data.parent_id == null && node.children) {
          this.showLoader = true;
          this.http
            .post(this.env.API_URL + "api/Rej/RejectionParent", {
              parent_rej_code: "0",
              parent_rej_desc:
                this.rejectionReasonForm.value.tree_name.toString(),
              active_rec:
                this.rejectionReasonForm.value.active_rec == "1" ? "1" : "0",
            })
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        }
        if (node.data.parent_id != null && node.children) {
          this.showLoader = true;
          this.http
            .post(this.env.API_URL + "api/LoanApplications/UpdateRejection", {
              loan_rej_code: "0",
              loan_rej_desc:
                this.rejectionReasonForm.value.tree_name.toString(),
              active_rec:
                this.rejectionReasonForm.value.active_rec == "1" ? "1" : "0",
              parent_rej_code: node.data.node_code.toString(),
            })
            .subscribe({
              next: (data) => {
                this.showLoader = false;
                this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
              },
              error: (err) => {
                console.log(err);
                this.alertServices.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        }
      }
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }
  clearForms() {
    this.isInserting = false;
    this.isEditing = false;
    this.isSubmitted = false;
    this.rejectionReasonForm.reset();
  }
}
